payload.raw:
{
  "layout": "comparison",
  "title": "创新领域现状",
  "subtitle": "柔性传感与手势识别技术路径对比",
  "left": {
    "heading": "本项目创新路径",
    "items": ["均致力于提升柔性传感与手势识别性能", "!全栈自研，实现硬件级漂移抑制与高精度识别", "仿水膜-鱼网结构液态金属薄膜，迟滞误差<5%", "光纤-IMU混合架构，目标精度0.1mm，延迟<20ms", "多模态闭环交互，集成压力梯度与温控反馈", "开发标准化协议，适配10余种国产XR平台"],
    "tone": "positive"
  },
  "right": {
    "heading": "现有技术局限",
    "items": ["均致力于提升柔性传感与手势识别性能", "!存在成本高、稳定性弱、算法封闭三重瓶颈", "碳基/聚合物传感器迟滞误差>15%，环境稳定性弱", "混合传感架构依赖频繁外部标定，实用性受限", "深度学习模型在复杂工况下精度不足92%，延迟超80ms", "多模态交互缺乏闭环设计，与国产平台深度适配稀缺"],
    "tone": "negative"
  }
}

